@namespace Lumeo

<div class="@CssClass" style="@StyleAttribute" @attributes="AdditionalAttributes">@ChildContent</div>

@code {
    /// <summary>Explicit CSS height (e.g. <c>"100vh"</c>, <c>"20rem"</c>) applied as an inline style. When unset, defaults to <c>h-full</c> so the element fills its parent's height.</summary>
    [Parameter] public string? Height { get; set; }

    /// <summary>When true, uses <c>inline-flex</c> instead of <c>flex</c> for the centering container. Default is <c>false</c>.</summary>
    [Parameter] public bool Inline { get; set; }

    /// <summary>The content to center both horizontally and vertically.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the root element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass
    {
        get
        {
            var display = Inline ? "inline-flex" : "flex";
            var height = string.IsNullOrEmpty(Height) ? "h-full" : null;
            return Cx.Merge(display, "items-center justify-center", height, Class);
        }
    }

    private string? StyleAttribute => !string.IsNullOrEmpty(Height) ? $"height: {Height}" : null;
}
